import React from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { TrendingUp, TrendingDown } from '@mui/icons-material';
import { LineChart } from '@mui/x-charts';
import response from './response.json';

interface Index {
  name: string;
  currentValue: number;
  change: number;
  changePercent: number;
  sparkline: number[];
}

interface IndicesData {
  indices: Index[];
}

export default function Widget() {
  const { indices } = response.data as IndicesData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: '#212121' }} elevation={3}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          {indices.map((index) => {
            const positive = index.change >= 0;
            return (
              <Box key={index.name}>
                <Stack direction="row" justifyContent="space-between" alignItems="center" sx={{ mb: 0.5 }}>
                  <Box>
                    <Typography variant="body2" sx={{ color: '#FFFFFF', fontWeight: 600 }}>
                      {index.name}
                    </Typography>
                    <Stack direction="row" alignItems="center" spacing={0.5} sx={{ mt: 0.5 }}>
                      {positive ? <TrendingUp sx={{ fontSize: 16, color: '#4CAF50' }} /> : <TrendingDown sx={{ fontSize: 16, color: '#F44336' }} />}
                      <Typography variant="body2" sx={{ color: positive ? '#4CAF50' : '#F44336' }}>
                        {positive ? '+' : ''}{index.change} ({index.changePercent}%)
                      </Typography>
                    </Stack>
                  </Box>
                  <Box textAlign="right">
                    <Typography variant="h6" sx={{ color: '#FFFFFF', fontWeight: 700 }}>
                      {index.currentValue.toLocaleString()}
                    </Typography>
                  </Box>
                </Stack>
                <LineChart
                  height={40}
                  series={[
                    {
                      data: index.sparkline,
                      color: positive ? '#4CAF50' : '#F44336',
                      curve: 'natural',
                      showMark: false,
                    },
                  ]}
                  xAxis={[{ data: index.sparkline.map((_, i) => i), hide: true }]}
                  margin={{ top: 5, bottom: 5, left: 0, right: 0 }}
                  sx={{
                    '& .MuiLineElement-root': {
                      strokeWidth: 1.5,
                    },
                  }}
                />
              </Box>
            );
          })}
        </Stack>
      </CardContent>
    </Card>
  );
}
